    /// Generate embeddings asynchronously for a list of text strings.
    ///
    /// This is the async counterpart to [`embed_texts`]. It offloads the blocking
    /// ONNX inference work to a dedicated blocking thread pool via Tokio's
    /// `spawn_blocking`, keeping the async executor free.
    ///
    /// Returns one embedding vector per input text in the same order.
    /// </summary>
    /// <param name="texts">Vec of strings to embed (owned, sent to blocking thread)</param>
    /// <param name="config">Embedding configuration specifying model, batch size, and normalization</param>
    /// <exception cref="KreuzbergException">- `KreuzbergError::MissingDependency` if ONNX Runtime is not installed
    /// - `KreuzbergError::Embedding` if the preset name is unknown, model download fails,
    ///   or the blocking inference task panics</exception>
    /// <example><code language="csharp">
    /// use kreuzberg::{embed_texts_async, EmbeddingConfig};
    ///
    /// let embeddings = embed_texts_async(
    ///     vec!["Hello!".to_string()],
    ///     &EmbeddingConfig::default(),
    /// ).await?;
    /// </code></example>
    /// <param name="texts"></param>
    /// <param name="config"></param>
    public static async Task<List<List<float>>> EmbedTextsAsync(List<string> texts, EmbeddingConfig config)
    {
        ArgumentNullException.ThrowIfNull(config);
        var textsJson = JsonSerializer.Serialize(texts, JsonOptions);
        var textsHandle = Marshal.StringToHGlobalAnsi(textsJson);
        var configJson = JsonSerializer.Serialize(config, JsonOptions);
        var configHandle = NativeMethods.EmbeddingConfigFromJson(configJson);
        return await Task.Run(() =>
        {
            var nativeResult = NativeMethods.EmbedTextsAsync(
                textsHandle,
                configHandle
            );
            if (nativeResult == IntPtr.Zero)
            {
                throw GetLastError();
            }
            var json = Marshal.PtrToStringUTF8(nativeResult);
            NativeMethods.FreeString(nativeResult);
            var returnValue = JsonSerializer.Deserialize<List<List<float>>>(json ?? "null", JsonOptions)!;
            Marshal.FreeHGlobal(textsHandle);
            NativeMethods.EmbeddingConfigFree(configHandle);
            return returnValue;
        });
    }

    /// <summary>
    /// Render a single PDF page to PNG bytes.
    ///
    /// Returns raw PNG-encoded bytes for the specified page at the given DPI.
    /// Uses pdf_oxide with tiny-skia for pure-Rust rendering.
    /// </summary>
    /// <param name="pdf_bytes">Raw PDF file bytes</param>
    /// <param name="page_index">Zero-based page index</param>
    /// <param name="dpi">Resolution in dots per inch (default: 150)</param>
    /// <param name="password">Optional password for encrypted PDFs</param>
    /// <exception cref="KreuzbergException">Returns `KreuzbergError::Parsing` if the PDF cannot be opened, authenticated,
    /// or rendered, or if `page_index` is out of range.</exception>
    /// <param name="pdfBytes"></param>
    /// <param name="pageIndex"></param>
    /// <param name="dpi">Optional.</param>
    /// <param name="password">Optional.</param>
    public static byte[] RenderPdfPageToPng(byte[] pdfBytes, ulong pageIndex, int? dpi, string? password)
    {
        ArgumentNullException.ThrowIfNull(pdfBytes);
        var rc = NativeMethods.RenderPdfPageToPng(
            pdfBytesHandle.AddrOfPinnedObject(),
            (UIntPtr)pdfBytes.Length,
            pageIndex,
            dpi.GetValueOrDefault(),
            password!,
            out var outPtr,
            out var outLen,
            out var outCap
        );
        if (rc != 0)
        {
            throw GetLastError();
        }
        var result = new byte[(int)outLen];
        Marshal.Copy(outPtr, result, 0, (int)outLen);
        NativeMethods.FreeBytes(outPtr, outLen, outCap);
        return result;
    }

